export const SOLUTIONS_DEMO_BADGES = [
  "Concept Demo",
  "Prototype Showcase",
  "Sample Industry Build",
  "Demo Case Study"
];

/** @type {Record<string, typeof SOLUTIONS_DEMO_CASES[number]>} */
export const SOLUTIONS_DEMO_CASES_BY_ROUTE_SLUG = Object.fromEntries(SOLUTIONS_DEMO_CASES.map((c) => [c.routeSlug, c]));

export function getDemoCaseByRouteSlug(slug) {
  return SOLUTIONS_DEMO_CASES_BY_ROUTE_SLUG[slug] ?? null;
}

export function getDemoCasesByFilter(filterId) {
  if (!filterId || filterId === "all") return SOLUTIONS_DEMO_CASES;
  return SOLUTIONS_DEMO_CASES.filter((c) => c.filterCategory === filterId);
}
